        public static void Initialize(IServiceProvider serviceProvider)
        {
            using (var context = new MovieFormContext(
                serviceProvider.GetRequiredService<DbContextOptions<MovieFormContext>>()))
            {
                // Check if database has been seeded
                if (context.Movies.Any())
                {
                    return; // Database has been seeded
                }

                // Seed Categories first
                var categories = new Dictionary<string, int>();
                var categoryList = new[] { "Action/Adventure", "Comedy", "Drama", "Family", "Horror/Suspense", "Miscellaneous", "Television", "VHS" };
                foreach (var catName in categoryList)
                {
                    var category = new Category { CategoryName = catName };
                    context.Categories.Add(category);
                }
                context.SaveChanges();

                // Reload categories with IDs
                foreach (var cat in context.Categories)
                {
                    categories[cat.CategoryName] = cat.CategoryId;
                }

                // Seed Ratings
                var ratings = new Dictionary<string, int>();
                var ratingList = new[] { "G", "PG", "PG-13", "R", "NR", "UR", "TV-G", "TV-PG", "TV-14", "TV-Y7", "R?" };
                foreach (var ratName in ratingList)
                {
                    var rating = new Rating { RatingName = ratName };
                    context.Ratings.Add(rating);
                }
                context.SaveChanges();

                // Reload ratings with IDs
                foreach (var rat in context.Ratings)
                {
                    ratings[rat.RatingName] = rat.RatingId;
                }

                // Seed Directors and Movies from CSV data
                var directors = new Dictionary<string, int>();

                // Helper method to get or create director
                int GetOrCreateDirector(string directorName)
                {
                    if (directors.ContainsKey(directorName))
                    {
                        return directors[directorName];
                    }

                    var director = new Director { DirectorName = directorName };
                    context.Directors.Add(director);
                    context.SaveChanges();
                    directors[directorName] = director.DirectorId;
                    return director.DirectorId;
                }

