                {
                    var directorId = GetOrCreateDirector(movie.Director);
                    var categoryId = categories[movie.Category];
                    var ratingId = ratings[movie.Rating];

                    context.Movies.Add(new Movie
                    {
                        Title = movie.Title,
                        Year = movie.Year,
                        DirectorId = directorId,
                        CategoryId = categoryId,
                        RatingId = ratingId,
                        Edited = movie.Edited,
                        LentTo = string.IsNullOrWhiteSpace(movie.LentTo) ? null : movie.LentTo,
                        Notes = string.IsNullOrWhiteSpace(movie.Notes) ? null : movie.Notes
                    });
                }

                context.SaveChanges();
